@ARTICLE{10.1038/s41467-020-18028-0,
	author = {Jin, J.-H. and Lee, K.-T. and Hong, J. and Lee, D. and Jang, E.-H. and Kim, J.-Y. and Lee, Y. and Lee, S.-H. and So, Y.-S. and Jung, K.-W. and Lee, D.-G. and Jeong, E. and Lee, M. and Jang, Y.-B. and Choi, Y. and Lee, M.H. and Kim, J.-S. and Yu, S.-R. and Choi, J.-T. and La, J.-W. and Choi, H. and Kim, S.-W. and Seo, K.J. and Lee, Y. and Thak, E.J. and Choi, J. and Averette, A.F. and Lee, Y.-H. and Heitman, J. and Kang, H.A. and Cheong, E. and Bahn, Y.-S.},
	title = {Genome-wide functional analysis of phosphatases in the pathogenic fungus Cryptococcus neoformans.},
	journal = {Nature Communications},
	year = {2020},
	abstract = {Phosphatases, together with kinases and transcription factors, are key components in cellular signalling networks. Here, we present a systematic functional analysis of the phosphatases in Cryptococcus neoformans, a fungal pathogen that causes life-threatening fungal meningoencephalitis. We analyse 230 signature-tagged mutant strains for 114 putative phosphatases under 30 distinct in vitro growth conditions, revealing at least one function for 60 of these proteins. Large-scale virulence and infectivity assays using insect and mouse models indicate roles in pathogenicity for 31 phosphatases involved in various processes such as thermotolerance, melanin and capsule production, stress responses, O-mannosylation, or retromer function. Notably, phosphatases Xpp1, Ssu72, Siw14, and Sit4 promote blood-brain barrier adhesion and crossing by C. neoformans. Together with our previous systematic studies of transcription factors and kinases, our results provide comprehensive insight into the pathobiological signalling circuitry of C. neoformans. © 2020, The Author(s). ER - ER - ER -},
	doi = {10.1038/s41467-020-18028-0},
	type = {JOUR}
}

@ARTICLE{10.1038/s41467-020-15329-2,
	author = {Lee, K.-T. and Hong, J. and Lee, D.-G. and Lee, M. and Cha, S. and Lim, Y.-G. and Jung, K.-W. and Hwangbo, A. and Lee, Y. and Yu, S.-J. and Chen, Y.-L. and Lee, J.-S. and Cheong, E. and Bahn, Y.-S.},
	title = {Fungal kinases and transcription factors regulating brain infection in Cryptococcus neoformans.},
	journal = {Nature Communications},
	year = {2020},
	abstract = {Cryptococcus neoformans causes fatal fungal meningoencephalitis. Here, we study the roles played by fungal kinases and transcription factors (TFs) in blood-brain barrier (BBB) crossing and brain infection in mice. We use a brain infectivity assay to screen signature-tagged mutagenesis (STM)-based libraries of mutants defective in kinases and TFs, generated in the C. neoformans H99 strain. We also monitor in vivo transcription profiles of kinases and TFs during host infection using NanoString technology. These analyses identify signalling components involved in BBB adhesion and crossing, or survival in the brain parenchyma. The TFs Pdr802, Hob1, and Sre1 are required for infection under all the conditions tested here. Hob1 controls the expression of several factors involved in brain infection, including inositol transporters, a metalloprotease, PDR802, and SRE1. However, Hob1 is dispensable for most cellular functions in Cryptococcus deuterogattii R265, a strain that does not target the brain during infection. Our results indicate that Hob1 is a master regulator of brain infectivity in C. neoformans. © 2020, The Author(s). ER - ER - ER -},
	doi = {10.1038/s41467-020-15329-2},
	type = {JOUR}
}

@ARTICLE{10.1126/sciadv.abb8783,
	author = {Li, Z. and Kim, K.S.},
	title = {RELATe enables genome-scale engineering in fungal genomics.},
	journal = {Science Advances},
	year = {2020},
	abstract = {CRISPR-Cas9-based screening with single-guide RNA (sgRNA) libraries has emerged as a revolutionary tool for comprehensive analysis of genetic elements. However, genome-scale sgRNA libraries are currently available only in a few model organisms. The traditional approach is to synthesize thousands to tens of thousands of sgRNAs, which is laborious and expensive. We have developed a simple method, RELATe (restriction/ligation coupled with Agrobacterium-mediated transformation), to generate sgRNA libraries from 10 μg of genomic DNA, targeting over 98% of the protein-coding genes in the human fungal pathogen Cryptococcus neoformans. Functional screens identified 142 potential C. neoformans genes contributing to blood-brain barrier penetration. We selected two cryptococcal genes, SFP1 and WDR1, for a proof-of-concept demonstration that RELATe-identified genes are relevant to C. neoformans central nervous system infection. Our RELATe method can be used in many other fungal species and is powerful and cost-effective for genome-wide high-throughput screening for elucidating functional genomics. Copyright © 2020 The Authors, some rights reserved. ER - ER - ER -},
	doi = {10.1126/sciadv.abb8783},
	type = {JOUR}
}

@ARTICLE{10.1016/j.celrep.2025.116658,
	author = {Wang, G. and Feng, C. and Ma, Z. and Zhao, L. and Yosri, M. and Wang, Y. and Gao, X. and Zhu, W. and Li, H. and Song, H. and Xia, J. and Meng, M. and Lu, H. and Zhang, L. and Chen, Z. and Sun, D.},
	title = {In toto imaging shows intravascular proliferation promotes transmigration of daughter cells during brain invasion of Cryptococcus neoformans.},
	journal = {Cell Reports},
	year = {2025},
	abstract = {Cryptococcus neoformans causes lethal meningoencephalitis. Although the mechanism of its blood-brain barrier (BBB) transmigration has been intensively studied, the predominant route remains unclear. We developed fTRACE, a whole-organ imaging workflow enabling in toto visualization of individual fungal cells in vivo, and found that C. neoformans can proliferate intravascularly before BBB transmigration. Importantly, daughter cells, not mother cells, predominantly transmigrate across the BBB. Intravascular proliferation depends on de novo purine biosynthesis. We created a non-proliferative fluorescent mutant to trace fungal fate in the brain and found that the majority of non-proliferative C. neoformans remained intravascular after prolonged brain infection, while the remainder induced local capillary pruning. Angiophagy occurred with low frequency. C. neoformans can be washed out from the brain vasculature, which is expedited by VEGFR-2 inhibition. This study elucidates a major brain invasion route of C. neoformans and provides an approach for studying host-pathogen interactions using in toto imaging. © 2025 The Author(s). Published by Elsevier Inc. This is an open access article under the CC BY-NC-ND license. http://creativecommons.org/licenses/by-nc-nd/4.0/ ER - ER - ER -},
	doi = {10.1016/j.celrep.2025.116658},
	type = {JOUR}
}

@ARTICLE{10.1038/s41551-021-00743-8,
	author = {Kim, J. and Lee, K.-T. and Lee, J.S. and Shin, J. and Cui, B. and Yang, K. and Choi, Y.S. and Choi, N. and Lee, S.H. and Lee, J.-H. and Bahn, Y.-S. and Cho, S.-W.},
	title = {Fungal brain infection modelled in a human-neurovascular-unit-on-a-chip with a functional blood–brain barrier},
	journal = {Nature Biomedical Engineering},
	year = {2021},
	abstract = {The neurovascular unit, which consists of vascular cells surrounded by astrocytic end-feet and neurons, controls cerebral blood flow and the permeability of the blood–brain barrier (BBB) to maintain homeostasis in the neuronal milieu. Studying how some pathogens and drugs can penetrate the human BBB and disrupt neuronal homeostasis requires in vitro microphysiological models of the neurovascular unit. Here we show that the neurotropism of Cryptococcus neoformans—the most common pathogen causing fungal meningitis—and its ability to penetrate the BBB can be modelled by the co-culture of human neural stem cells, brain microvascular endothelial cells and brain vascular pericytes in a human-neurovascular-unit-on-a-chip maintained by a stepwise gravity-driven unidirectional flow and recapitulating the structural and functional features of the BBB. We found that the pathogen forms clusters of cells that penetrate the BBB without altering tight junctions, suggesting a transcytosis-mediated mechanism. The neurovascular-unit-on-a-chip may facilitate the study of the mechanisms of brain infection by pathogens, and the development of drugs for a range of brain diseases. © 2021, The Author(s), under exclusive licence to Springer Nature Limited. ER - ER - ER -},
	doi = {10.1038/s41551-021-00743-8},
	type = {JOUR}
}
